// SecureAuthStorage.js
import * as SecureStore from 'expo-secure-store';

const KEYS = {
  AUTH_TOKEN: 'auth_token',
  REFRESH_TOKEN: 'refresh_token',
  USER_ID: 'user_id',
  SESSION_EXPIRY: 'session_expiry',
};

// Non-sensitive user display data key (stored separately)
const USER_DISPLAY_KEY = 'user_display_data';

export const SecureAuthStorage = {
  async saveAuthData(authToken, refreshToken, userId, expiresIn) {
    try {
      const expiry = Date.now() + expiresIn * 1000;
      await SecureStore.setItemAsync(KEYS.AUTH_TOKEN, authToken);
      await SecureStore.setItemAsync(KEYS.REFRESH_TOKEN, refreshToken);
      await SecureStore.setItemAsync(KEYS.USER_ID, userId);
      await SecureStore.setItemAsync(KEYS.SESSION_EXPIRY, expiry.toString());
    } catch (error) {
      console.error('Failed to save auth data securely');
      throw new Error('SECURE_STORAGE_WRITE_FAILED');
    }
  },

  async getAuthToken() {
    try {
      const expiry = await SecureStore.getItemAsync(KEYS.SESSION_EXPIRY);
      if (expiry && Date.now() > parseInt(expiry, 10)) {
        // Token expired, attempt refresh
        return null;
      }
      return await SecureStore.getItemAsync(KEYS.AUTH_TOKEN);
    } catch (error) {
      console.error('Failed to retrieve auth token');
      return null;
    }
  },

  async getRefreshToken() {
    try {
      return await SecureStore.getItemAsync(KEYS.REFRESH_TOKEN);
    } catch (error) {
      console.error('Failed to retrieve refresh token');
      return null;
    }
  },

  async getUserId() {
    try {
      return await SecureStore.getItemAsync(KEYS.USER_ID);
    } catch (error) {
      console.error('Failed to retrieve user ID');
      return null;
    }
  },

  async clearAll() {
    try {
      await Promise.all(
        Object.values(KEYS).map((key) => SecureStore.deleteItemAsync(key))
      );
    } catch (error) {
      console.error('Failed to clear secure storage');
    }
  },
};

export default SecureAuthStorage;